import axios from 'axios';

const API_URL = 'http://localhost:8080/api/product-materials';

export const linkMaterialToProduct = (productId, materialId, quantity) =>
  axios.post(`${API_URL}`, {
    productId,
    materialId,
    quantity
  });

export const getMaterialsByProduct = (productId) =>
  axios.get(`${API_URL}/product/${productId}`);

export const deleteProductMaterial = (id) =>
  axios.delete(`${API_URL}/${id}`);
